LANGUAGE sql
IMMUTABLE
PARALLEL SAFE
AS $$
  -- Cumulative equity curve: (value_at(anchor + days) / value_at(anchor)) - 1.
  -- Returns NULL if either anchor or anchor+days is missing from the series.
